const jwt = require('jsonwebtoken');
const https = require('https');

// Read environment variables
const runId = process.env.ZEALT_RUN_ID;
const magicbellEmail = process.env.MAGICBELL_EMAIL;
const apiKey = process.env.MAGICBELL_API_KEY;
const secretKey = process.env.MAGICBELL_SECRET_KEY;

// Derive user details
const externalId = `user-topic-sub-${runId}`;
const [localPart, domain] = magicbellEmail.split('@');
const userEmail = `${localPart}+topic-sub-${runId}@${domain}`;
const topicName = `updates-${runId}`;

console.log(`Run ID: ${runId}`);
console.log(`External ID: ${externalId}`);
console.log(`User Email: ${userEmail}`);
console.log(`Topic Name: ${topicName}`);

// Generate User JWT using the correct MagicBell format
// Payload: user_external_id, user_email, api_key
const userJwtPayload = {
  user_external_id: externalId,
  user_email: userEmail,
  api_key: apiKey,
};

const userJwt = jwt.sign(userJwtPayload, secretKey, { algorithm: 'HS256' });
console.log(`User JWT: ${userJwt}`);

// Helper function to make HTTPS requests
function makeRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        resolve({ statusCode: res.statusCode, headers: res.headers, body: data });
      });
    });
    req.on('error', reject);
    if (body) {
      req.write(JSON.stringify(body));
    }
    req.end();
  });
}

